PREFIX hetio: <https://het.io/schema/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?gene ?geneLabel ?chromosome
WHERE {
  ?gene a hetio:Gene ;
        rdfs:label "HTR3B" ;
        hetio:chromosome ?chromosome .
  BIND("HTR3B" AS ?geneLabel)
}
LIMIT 200

